import React from "react";
import { useNavigate, useParams } from "react-router-dom";
import { FaUserCircle } from "react-icons/fa";
import styles from "./staffdashboard.module.css"; // Ensure you have this CSS file

const StaffDashboard = () => {
  const navigate = useNavigate();
  const { username } = useParams(); // Capture the username from URL

  return (
    <div className={styles.dashboard}>
      <div className={styles.header}>
        <img src="/assets/ODCSE Logo.png" alt="Logo" className={styles.logo} />
        <FaUserCircle 
          className={styles.userIcon} 
          onClick={() => navigate("/profile")} 
        />
      </div>
      <h1 className={styles.title}>Welcome {username} to Staff Dashboard</h1>
      <p className={styles.description}>
        This is the staff panel where you can manage student data, monitor attendance, and perform other staff activities.
      </p>
    </div>
  );
};

export default StaffDashboard;
